/* ===== Feed Styles ===== */

.feed {
  max-width: 720px;
  margin: 0 auto;
  padding: 32px 24px;
  text-align: left;
}

.feed h1 {
  font-size: 32px;
  letter-spacing: -0.5px;
  margin: 0 0 24px;
}

.feed-list {
  list-style: none;
  padding: 0;
  margin: 0;
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.feed-item {
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 16px 20px;
  background: var(--bg);
  transition: box-shadow 0.2s;
}

.feed-item:hover {
  box-shadow: var(--shadow);
}

.feed-item-title {
  font-size: 18px;
  margin: 0 0 4px;
  line-height: 1.3;
}

.feed-item-author {
  font-size: 13px;
  color: var(--accent);
  font-weight: 500;
}

.feed-item-excerpt {
  margin: 8px 0 0;
  font-size: 15px;
  line-height: 1.5;
  color: var(--text);
}

.feed-actions {
  margin-top: 24px;
  text-align: center;
}

.load-more-btn {
  font-size: 16px;
  padding: 10px 28px;
  border-radius: 6px;
  color: #fff;
  background: var(--accent);
  border: none;
  cursor: pointer;
  transition: opacity 0.2s;
}

.load-more-btn:hover:not(:disabled) {
  opacity: 0.85;
}

.load-more-btn:disabled {
  opacity: 0.6;
  cursor: not-allowed;
}

.status-message {
  text-align: center;
  color: var(--text);
  font-size: 16px;
  padding: 40px 0;
}

.status-message.error {
  color: #e53e3e;
}

